mapper.delete:

delete from kh_disease_symptom_items
where disease_id = #{diseaseId,jdbcType=BIGINT}
  and symptom_index = #{symptomIndex,jdbcType=INTEGER}

mapper.update:

update kh_disease_symptom_items
set disease_name = #{diseaseName,jdbcType=VARCHAR},
  language = #{language,jdbcType=VARCHAR},
  symptom = #{symptom,jdbcType=VARCHAR},
  relationship = #{relationship,jdbcType=VARCHAR},
  create_time = #{createTime,jdbcType=TIMESTAMP},
  update_time = #{updateTime,jdbcType=TIMESTAMP}
where disease_id = #{diseaseId,jdbcType=BIGINT}
  and symptom_index = #{symptomIndex,jdbcType=INTEGER}

mapper.select:

select disease_id, symptom_index, disease_name, language, symptom, relationship, 
create_time, update_time
from kh_disease_symptom_items
where disease_id = #{diseaseId,jdbcType=BIGINT}
  and symptom_index = #{symptomIndex,jdbcType=INTEGER}
